## CSS Value Field

A field that captures a CSS value (e.g. length, color, keyword)

### Usage

```ts
import { CardDef, field, contains } from 'https://cardstack.com/base/card-api';
import CssValueField from 'https://cardstack.com/base/css-value';

export class Example extends CardDef {
  @field value = contains(CssValueField);
}
```
